{
	int n;
    cin>>n;
    for(int i=1;i<=n;i++)
	{
        cin>>i;
        cin>>s;
        int map=0;
        while(cin>>t && t!=0)
        {
        	map=max(ans[t],map);
		}
        ans[i]=map+s;
        int maxx=max(ans[i],maxx);
    } 
    cout<<maxx;
    return 0;
 }
